  ('10000000-0000-0000-0000-000000000006', '2026년 청년창업사관학교', '중소벤처기업부', 'education', '만 39세 이하 (예비)창업자', '만 39세 이하, 창업 3년 이내 또는 예비창업자', '교육+멘토링+사업화자금 최대 1억원', '2026-03-01', '2026-03-31', ARRAY['입교신청서', '사업계획서', '주민등록등본', '졸업증명서'], '청년 창업자 대상 집중 보육 프로그램.', 'https://start.kosmes.or.kr', 'open', 'medium', 14, 'K-Startup'),
